Write-Host "=== Staging Packages ===" -ForegroundColor Cyan
git add packages/

Write-Host "`n=== Staging Scripts ===" -ForegroundColor Cyan
git add scripts/ 2>$null

Write-Host "`n=== Staging Root Files ===" -ForegroundColor Cyan
git add package.json pnpm-lock.yaml 2>$null

Write-Host "`n=== Checking Remaining Unstaged ===" -ForegroundColor Yellow
$unstaged = git status --short | Where-Object { $_ -notmatch "^[AMD]" }
if ($unstaged) {
    Write-Host "Unstaged files:" -ForegroundColor Yellow
    $unstaged | Select-Object -First 10
} else {
    Write-Host "All files staged!" -ForegroundColor Green
}

Write-Host "`n=== Total Staged Files ===" -ForegroundColor Green
(git diff --cached --name-only | Measure-Object).Count
